import type { ReactNode } from "react";

/** Pair with the Problem and Solution components installed alongside:
 *
 * ```mdx
 * <Problem>Decks rot in proprietary tools.</Problem>
 * <Solution>Slides are files; the repo is the deck.</Solution>
 * ```
 */
export default function ProblemSolutionLayout({
  title,
  children,
}: {
  title?: string;
  children: ReactNode;
}) {
  return (
    <main className="flex h-full flex-col gap-10 p-24">
      {title ? (
        <h1 className="font-bold text-6xl tracking-tight">{title}</h1>
      ) : null}
      <div className="grid flex-1 grid-cols-2 items-stretch gap-10">
        {children}
      </div>
    </main>
  );
}

import type { ReactNode } from "react";

export default function Problem({ children }: { children: ReactNode }) {
  return (
    <section className="flex flex-col gap-4 rounded-2xl border-(--color-foreground)/15 border-2 p-10">
      <span className="font-semibold text-(--color-foreground)/50 text-sm uppercase tracking-[0.2em]">
        Problem
      </span>
      <div className="text-2xl leading-relaxed">{children}</div>
    </section>
  );
}

import type { ReactNode } from "react";

export default function Solution({ children }: { children: ReactNode }) {
  return (
    <section className="flex flex-col gap-4 rounded-2xl border-(--color-primary)/50 border-2 bg-(--color-primary)/5 p-10">
      <span className="font-semibold text-(--color-primary) text-sm uppercase tracking-[0.2em]">
        Solution
      </span>
      <div className="text-2xl leading-relaxed">{children}</div>
    </section>
  );
}
